const item = $input.first().json;
const body = item.body || {};

const name = (body.name || '').trim() || 'Not provided';
const businessName = (body.businessName || '').trim() || 'Not provided';
const email = (body.email || '').trim();
const phone = (body.phone || '').trim();
const segment = body.segment || 'Not specified';
const volume = body.volume || 'Not specified';
const sourcePage = (body.sourcePage || '').replace('/', '') || 'unknown';

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const phoneRegex = /^[+]?[\d\s-]{7,15}$/;

const emailValid = email ? emailRegex.test(email) : true;
const phoneValid = phoneRegex.test(phone);
const isValid = name !== 'Not provided' && phoneValid;

let validationReason = '';
if (!isValid) {
  const reasons = [];
  if (name === 'Not provided') reasons.push('missing name');
  if (!phoneValid) reasons.push('invalid or missing phone');
  if (!emailValid) reasons.push('malformed email');
  validationReason = reasons.join(', ');
}

const submittedAtRaw = body.submittedAt || new Date().toISOString();
let submittedAt;
try {
  submittedAt = new Date(submittedAtRaw).toLocaleString('en-IN', {
    timeZone: 'Asia/Kolkata',
    day: '2-digit',
    month: 'short',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: true
  });
} catch (e) {
  submittedAt = submittedAtRaw;
}

return [{
  json: {
    body: {
      name,
      businessName,
      email,
      phone,
      segment,
      volume,
      submittedAt,
      sourcePage
    },
    leadsource: 'website form',
    status: isValid ? 'new lead' : 'invalid lead',
    isValid,
    validationReason,
    emailValid,
    phoneValid
  }
}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.recentSubmissions) staticData.recentSubmissions = {};

const item = $input.first().json;
const key = `${(item.body.email || '').toLowerCase()}|${item.body.phone}`;
const now = Date.now();
const windowMs = 5 * 60 * 1000;

for (const k of Object.keys(staticData.recentSubmissions)) {
  if (now - staticData.recentSubmissions[k] > windowMs) {
    delete staticData.recentSubmissions[k];
  }
}

const isDuplicate = !!staticData.recentSubmissions[key];
staticData.recentSubmissions[key] = now;

return [{
  json: {
    ...item,
    isDuplicate
  }
}];

